import React from "react"
import { education } from "../constants"
import { GraduationCap, Calendar } from "lucide-react"
import { motion } from "framer-motion"

const Education = () => {

  return (
    <section id="education" className="py-24 px-6 sm:px-10 md:px-24">

      {/* Title */}

      <motion.h2
        initial={{ opacity: 0, y: 40 }}
        whileInView={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
        className="text-4xl md:text-5xl font-bold text-center mb-20 italic"
      >
        Education
      </motion.h2>


      {/* Timeline container */}

      <div className="max-w-4xl mx-auto relative">

        {/* Timeline glowing line */}

        <div className="absolute left-4 top-0 h-full w-[2px] bg-gradient-to-b from-accent/80 via-accent/40 to-transparent"></div>


        {education.map((edu, index) => (

          <motion.div
            key={index}
            initial={{ opacity: 0, y: 60 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: index * 0.1 }}
            className="relative pl-12 mb-12"
          >

            {/* Animated Node */}

            <div className="absolute left-0 top-2 flex items-center justify-center w-8 h-8 rounded-full bg-accent shadow-lg shadow-accent/40 animate-pulse">

              <GraduationCap size={16} className="text-white"/>

            </div>


            {/* Glass Card */}

            <div
              className="
                p-8
                text-left
                backdrop-blur-xl
                border border-gray-200 dark:border-white/10
                rounded-2xl
                hover:-translate-y-1
                hover:border-accent
                hover:shadow-xl hover:shadow-accent/30
                transition duration-500
              "
            >

              {/* Degree */}

              <h3 className="text-xl font-bold leading-tight text-black dark:text-white">

                {edu.degree}

              </h3>


              {/* Accent divider */}

              <div className="w-16 h-0.5 bg-accent mt-2 mb-4 rounded"></div>


              <div className="mb-4 space-y-2 text-sm text-gray-700 dark:text-gray-300">

                {/* Field */}

                {edu.field && (
                  <p className="text-accent">{edu.field}</p>
                )}

                {/* Institution */}

                <p>{edu.institution}</p>


                {/* Year */}

                <div className="flex items-center gap-2 text-xs uppercase tracking-wide">

                  <Calendar size={14} className="text-accent"/>

                  {edu.year}

                </div>

              </div>


              {(edu.CGPA || edu.percentage) && (

                <div className="mb-3 flex flex-wrap gap-x-4 gap-y-1 text-sm">

                  {edu.CGPA && <p>CGPA: {edu.CGPA}</p>}

                  {edu.percentage && <p>Percentage: {edu.percentage}</p>}

                </div>

              )}


              {/* Description */}

              <p className="text-sm text-gray-700 dark:text-gray-300 leading-relaxed">

                {edu.description}

              </p>

            </div>

          </motion.div>

        ))}

      </div>

    </section>
  )
}

export default Education

import React, { useState, useEffect } from 'react';
import Lottie from 'lottie-react';
import { ChevronDown } from 'lucide-react';
import useTypewriter from '../hooks/useTypewriter';
import MagneticButton from './MagneticButton';
// Import your animation file
import robotAnimation from '../assets/animations/hello.json';

const Hero = () => {
  const phrases = ["Web Developer", "C++ Enthusiast", "Full Stack Developer"];
  const text = useTypewriter(phrases);

  return (
    <section id="home" className="relative h-screen flex flex-col lg:flex-row items-center justify-between px-10 md:px-24 pt-20 overflow-hidden">
      
      {/* Background Shooting Star */}
      <div className="shooting-star top-32 right-1/4"></div>

      {/* LEFT SIDE: Text Content */}
      <div className="z-10 flex-1">
        <h1 className="text-5xl md:text-7xl font-bold leading-tight">
          Hi, I'm <span className="text-accent italic">Dhriti Gupta</span>
        </h1>
        
        <div className="h-12 mt-4">
          <p className="text-2xl md:text-3xl font-mono text-secondary">
            {text}<span className="text-accent animate-pulse font-bold">|</span>
          </p>
        </div>
        
        <div className="flex flex-wrap gap-4 mt-12">
          <MagneticButton href="#projects" className="bg-accent hover:bg-accent/80 px-8 py-3 rounded-full font-bold transition-all shadow-lg shadow-accent/20 text-white">
            View My Work
          </MagneticButton>
          <MagneticButton href="#skills" className="border border-accent text-accent hover:bg-accent hover:text-white px-8 py-3 rounded-full font-bold transition-all">
            Explore My Skills
          </MagneticButton>
        </div>
      </div>

      {/* RIGHT SIDE: YOUR LOTTIE ANIMATION */}
      <div className="flex-1 flex justify-center lg:justify-end">
        <div className="w-[300px] md:w-[500px] drop-shadow-[0_0_30px_rgba(145,94,255,0.3)]">
          <Lottie 
            animationData={robotAnimation} 
            loop={true} 
            className="w-full h-full"
          />
        </div>
      </div>

      {/* SCROLL HINT */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex flex-col items-center opacity-40">
        <p className="text-[10px] uppercase tracking-[0.3em] font-bold mb-2 text-white">Scroll Down !!!</p>
        <ChevronDown size={20} className="animate-bounce text-white" />
      </div>

    </section>
  );
};

export default Hero;

import { motion } from "framer-motion";
import { Github, Link } from "lucide-react";

const ProjectModal = ({ project, onClose }) => {

  if (!project) return null;

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6"
    >
      <motion.div
        initial={{ scale: 0.8 }}
        animate={{ scale: 1 }}
        className="bg-[#0a1224] rounded-2xl p-8 max-w-xl w-full border border-white/10"
      >

        <h2 className="text-3xl font-bold mb-4">{project.name}</h2>

        <p className="text-secondary mb-6">{project.description}</p>

        <div className="flex gap-4">

          {project.live && (
            <a
              href={project.live}
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-2 bg-accent px-4 py-2 rounded-lg"
            >
              <Link size={16}/> Live
            </a>
          )}

          <a
            href={project.github}
            target="_blank"
            rel="noreferrer"
            className="flex items-center gap-2 border border-white/20 px-4 py-2 rounded-lg"
          >
            <Github size={16}/> Github
          </a>

        </div>

        <button
          onClick={onClose}
          className="mt-6 text-sm text-secondary hover:text-white"
        >
          Close
        </button>

      </motion.div>
    </motion.div>
  );
};

export default ProjectModal;

import React from 'react';
import { motion } from 'framer-motion';

const Reveal = ({ children }) => {
  return (
    <motion.div
      initial={{ opacity: 0, y: 50 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-100px" }}
      transition={{ duration: 0.8, ease: "easeOut" }}
    >
      {children}
    </motion.div>
  );
};

export default Reveal;

import { useState, useEffect } from 'react';

const useActiveSection = (sectionIds, offset = 0) => {
  const [activeSection, setActiveSection] = useState("");

  useEffect(() => {
    const observers = [];
    const callback = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observerOptions = {
      root: null,
      rootMargin: `${offset}px 0px 0px 0px`,
      threshold: 0.5, // Trigger when 50% of the section is visible
    };

    const currentObserver = new IntersectionObserver(callback, observerOptions);

    sectionIds.forEach((id) => {
      const element = document.getElementById(id);
      if (element) {
        currentObserver.observe(element);
      }
    });

    return () => currentObserver.disconnect();
  }, [sectionIds, offset]);

  return activeSection;
};

export default useActiveSection;

